// Extraire les titres des actualites (items[] = sortie RSS, prendre les 5 premiers)
const headlines = items.slice(0, 5).map(item => item.json.title);

// Recuperer la meteo via $() (reference au node en amont)
const weather = $('Get Weather').first().json;
const temp = Math.round(weather.current?.temperature_2m || 0);
const weatherCode = weather.current?.weather_code || 0;
const weatherDescriptions = {
  0: 'ciel degage', 1: 'peu nuageux', 2: 'partiellement nuageux', 3: 'couvert',
  45: 'brouillard', 48: 'brouillard givrant',
  51: 'bruine legere', 53: 'bruine', 55: 'bruine forte',
  61: 'pluie legere', 63: 'pluie', 65: 'pluie forte',
  71: 'neige legere', 73: 'neige', 75: 'neige forte',
  80: 'averses legeres', 81: 'averses', 82: 'averses fortes',
  95: 'orage', 96: 'orage avec grele'
};
const condition = weatherDescriptions[weatherCode] || 'inconnu';

// Recuperer la citation via $()
const quoteRaw = $('Get Quote').first().json;
const quoteData = Array.isArray(quoteRaw) ? quoteRaw[0] : quoteRaw;
const quote = quoteData?.q || 'Citation indisponible';
const author = quoteData?.a || 'Inconnu';

// Date du jour en francais
const now = new Date();
const dateStr = now.toLocaleDateString('fr-FR', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

// Construire le prompt pour Claude
const prompt = `Tu es un assistant francophone chaleureux. Genere un briefing matinal personnalise en francais.

Voici les donnees du jour (${dateStr}) :

METEO A PARIS :
- Temperature : ${temp}°C
- Condition : ${condition}

CITATION DU JOUR :
\"${quote}\" - ${author}

TITRES D'ACTUALITE (Le Monde) :
${headlines.map((h, i) => `${i + 1}. ${h}`).join('\n')}

Redige un court paragraphe (4-6 phrases) qui :
1. Salue l'utilisateur et mentionne la meteo
2. Integre naturellement la citation du jour
3. Resume les grandes tendances des actualites
4. Termine sur une note positive et motivante

Style : amical, informatif, comme un ami cultive qui resume la matinee.`;

// Corps de la requete Claude
const claudeBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 1024,
  messages: [
    { role: 'user', content: prompt }
  ]
};

return [{
  json: {
    claudeBody,
    raw: {
      date: dateStr,
      headlines,
      temperature: temp,
      condition,
      weatherCode,
      quote,
      author
    }
  }
}];

// Extraire la reponse de Claude
const claudeResponse = items[0].json;
const resumeIA = claudeResponse.content?.[0]?.text || claudeResponse.error?.message || 'Resume indisponible';

// Recuperer les donnees brutes du node Build Prompt
const raw = $('Build Prompt').first().json.raw;

return [{
  json: {
    briefing: {
      date: raw.date,
      meteo: {
        ville: 'Paris',
        temperature: `${raw.temperature}°C`,
        condition: raw.condition
      },
      citation: {
        texte: raw.quote,
        auteur: raw.author
      },
      actualites: raw.headlines,
      resume_ia: resumeIA,
      modele: 'claude-sonnet-4-20250514'
    }
  }
}];
